'use client';

import React from 'react';
import { Clock, UserCheck, AlertTriangle } from 'lucide-react';

const alerts = [
    {
        id: 1,
        text: 'BK-1049 needs nurse assignment in 30 mins',
        timestamp: '5 mins ago',
        icon: Clock,
        color: 'text-red-500',
        bgColor: 'bg-red-50'
    },
    {
        id: 2,
        text: 'Priya S. requested shift change for tomorrow',
        timestamp: '15 mins ago',
        icon: UserCheck,
        color: 'text-blue-500',
        bgColor: 'bg-blue-50'
    },
    {
        id: 3,
        text: 'Low nurse availability in Porur area',
        timestamp: '1 hour ago',
        icon: AlertTriangle,
        color: 'text-amber-500',
        bgColor: 'bg-amber-50'
    },
];

const UrgentAlerts = () => {
    return (
        <div className="bg-white rounded-[24px] border border-gray-100 p-8 shadow-sm">
            <h2 className="text-[18px] font-bold text-gray-900 mb-8">Urgent Alerts</h2>

            <div className="space-y-8">
                {alerts.map((alert) => (
                    <div key={alert.id} className="flex gap-5 group cursor-pointer">
                        <div className={`w-12 h-12 rounded-full flex-shrink-0 flex items-center justify-center transition-all group-hover:scale-110 ${alert.bgColor} border border-white shadow-sm shadow-black/5`}>
                            <alert.icon size={22} className={alert.color} strokeWidth={2.5} />
                        </div>
                        <div className="flex-1 min-w-0">
                            <p className="text-[14px] font-bold text-gray-800 leading-tight group-hover:text-teal-600 transition-colors">
                                {alert.text}
                            </p>
                            <p className="text-[12px] text-gray-400 mt-1.5 font-medium">{alert.timestamp}</p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default UrgentAlerts;
