'use client';

import React from 'react';
import { MapPin } from 'lucide-react';

const nurses = [
    { id: 1, name: 'Sangeetha V.', specialty: 'ICU Specialist', location: 'Anna Nagar', initials: 'SV', color: 'bg-teal-600' },
    { id: 2, name: 'Ramya P.', specialty: 'Elderly Care', location: 'T Nagar', initials: 'RP', color: 'bg-[#1E5F74]' },
    { id: 3, name: 'Divya L.', specialty: 'Pediatric Care', location: 'Adyar', initials: 'DL', color: 'bg-[#1D3E53]' },
    { id: 4, name: 'Nithya K.', specialty: 'Post-Surgery', location: 'Velachery', initials: 'NK', color: 'bg-[#254B62]' },
];

const AvailableNurses = () => {
    return (
        <div className="bg-white rounded-[24px] border border-gray-100 p-8 shadow-sm mt-8">
            <h2 className="text-[18px] font-bold text-gray-900 mb-8">Available Nurses Today</h2>

            <div className="space-y-8">
                {nurses.map((nurse) => (
                    <div key={nurse.id} className="flex gap-4 items-center group cursor-pointer">
                        <div className={`w-12 h-12 rounded-full flex-shrink-0 flex items-center justify-center text-white font-extrabold text-[13px] shadow-md transition-all group-hover:scale-110 ${nurse.color} border-2 border-white ring-1 ring-gray-100`}>
                            {nurse.initials}
                        </div>
                        <div className="flex-1 min-w-0">
                            <div className="flex flex-col gap-1.5">
                                <p className="text-[14px] font-bold text-gray-800 truncate group-hover:text-teal-600 transition-colors">{nurse.name}</p>
                                <div>
                                    <span className="bg-blue-50/50 text-blue-600 px-3 py-1 rounded-lg text-[10px] font-extrabold border border-blue-100/30 uppercase tracking-wider">
                                        {nurse.specialty}
                                    </span>
                                </div>
                                <div className="flex items-center gap-1.5 text-gray-400">
                                    <MapPin size={12} strokeWidth={2.5} />
                                    <p className="text-[12px] font-semibold">{nurse.location}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default AvailableNurses;
